#nullable enable // autogenerated

using MVZ2.GameContent.Buffs.Enemies;
using MVZ2.GameContent.Effects;
using MVZ2.GameContent.Entities;
using MVZ2.Vanilla.Audios;
using MVZ2Logic.Level;
using PVZEngine.Buffs;
using PVZEngine.Damages;
using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Enemies
{
    [AutoEntityBehaviourDefinition(VanillaEnemyNames.wispFly)]
    public class WispFly : EntityBehaviourDefinition
    {
        public WispFly(string nsp, string name) : base(nsp, name)
        {
        }
        public override void Init(Entity entity)
        {
            base.Init(entity);
            var buff = entity.AddBuff<FlyBuff>();
            buff.SetProperty(FlyBuff.PROP_TARGET_HEIGHT, 20f);

            entity.Level.AddLoopSoundEntity(VanillaSoundID.flySwarm, entity.ID);
        }

        public override void PostDeath(Entity entity, DeathInfo deathInfo)
        {
            base.PostDeath(entity, deathInfo);
            entity.Spawn(VanillaEffectID.cursedFireburn, entity.GetCenter());
            entity.Remove();
        }
    }
}
